// Simple terminal-based chess engine in C
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char board[8][8] = {
    {'r','n','b','q','k','b','n','r'},
    {'p','p','p','p','p','p','p','p'},
    {'.','.','.','.','.','.','.','.'},
    {'.','.','.','.','.','.','.','.'},
    {'.','.','.','.','.','.','.','.'},
    {'.','.','.','.','.','.','.','.'},
    {'P','P','P','P','P','P','P','P'},
    {'R','N','B','Q','K','B','N','R'}
};

void print_board() {
    printf("  a b c d e f g h\n");
    for(int i = 0; i < 8; i++) {
        printf("%d ", 8 - i);
        for(int j = 0; j < 8; j++) printf("%c ", board[i][j]);
        printf("%d\n", 8 - i);
    }
    printf("  a b c d e f g h\n");
}

int main() {
    char move[5];
    while(1) {
        print_board();
        printf("Enter move (e.g., e2e4): ");
        if(scanf("%s", move) != 1) break;

        int c1 = move[0] - 'a';
        int r1 = 8 - (move[1] - '0');
        int c2 = move[2] - 'a';
        int r2 = 8 - (move[3] - '0');

        if(c1 >= 0 && c1 < 8 && r1 >= 0 && r1 < 8 && c2 >= 0 && c2 < 8 && r2 >= 0 && r2 < 8) {
            board[r2][c2] = board[r1][c1];
            board[r1][c1] = '.';
        } else {
            printf("Invalid move format.\n");
        }
    }
    return 0;
