// Brainfuck interpreter in C
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(int argc, char *argv[]) {
    if (argc < 2) return 1;
    FILE *f = fopen(argv[1], "r");
    if (!f) return 1;
    fseek(f, 0, SEEK_END);
    long size = ftell(f);
    rewind(f);
    char *code = malloc(size + 1);
    fread(code, 1, size, f);
    code[size] = 0;
    fclose(f);

    unsigned char tape[30000] = {0};
    int ptr = 0;
    int pc = 0;
    int loop_stack[1000];
    int stack_ptr = 0;

    while (code[pc]) {
        switch (code[pc]) {
            case '>': ptr++; break;
            case '<': ptr--; break;
            case '+': tape[ptr]++; break;
            case '-': tape[ptr]--; break;
            case '.': putchar(tape[ptr]); break;
            case ',': tape[ptr] = getchar(); break;
            case '[':
                if (tape[ptr] == 0) {
                    int depth = 1;
                    while (depth > 0) {
                        pc++;
                        if (code[pc] == '[') depth++;
                        else if (code[pc] == ']') depth--;
                    }
                } else {
                    loop_stack[stack_ptr++] = pc;
                }
                break;
            case ']':
                if (tape[ptr] != 0) {
                    pc = loop_stack[stack_ptr - 1];
                } else {
                    stack_ptr--;
                }
                break;
        }
        pc++;
    }
    free(code);
    return 0;
